head.b:skin:
/* Variables de Color */
:root {
    --primary: #2c3e50;
    --secondary: #34495e;
    --bg: #f5f5f5;
    --text: #333;
}

body {
    font-family: 'Inter', sans-serif;
    margin: 0;
    background-color: var(--bg);
    color: var(--text);
}
.container {
    max-width: 800px;
    margin: 0 auto;
    padding: 20px;
}
header {
    background-color: var(--primary);
    color: white;
    padding: 20px 0;
    text-align: center;
}
nav {
    background-color: var(--secondary);
    overflow: hidden;
}
nav ul {
    list-style: none;
    padding: 0;
    margin: 0;
    display: flex;
    justify-content: center;
}
nav ul li a {
    color: white;
    text-decoration: none;
    padding: 15px 20px;
    display: block;
}
nav ul li a:hover {
    background-color: #576a7f;
}
.content {
    background: white;
    padding: 20px;
    margin-top: 20px;
    box-shadow: 0 0 10px rgba(0,0,0,0.1);
    border-radius: 8px;
}
.btn {
    display: inline-block;
    background: var(--primary);
    color: white;
    padding: 10px 20px;
    text-decoration: none;
    border-radius: 5px;
    margin-top: 10px;
}
footer {
    text-align: center;
    padding: 20px 0;
    background: var(--primary);
    color: white;
    margin-top: 40px;
}
/* Mobile Nav */
.mobile-nav { display: none; }
@media (max-width: 768px) {
    nav { display: none; }
    .mobile-nav {
        display: flex;
        position: fixed;
        bottom: 0;
        width: 100%;
        background: var(--secondary);
        z-index: 999;
        justify-content: space-around;
        list-style: none;
        padding: 10px 0;
        margin: 0;
    }
    .mobile-nav li a {
        color: white;
        text-decoration: none;
        font-size: 12px;
        text-align: center;
    }
    body { padding-bottom: 60px; }
}
